const express = require("express");
const router = express.Router();
const multer = require("multer");
const { body, validationResult } = require("express-validator");
const authMiddleware = require("../middleware/authMiddleware");
const {
  uploadDocument,
  getDocuments,
  getDocumentById,
  verifyDocument,
  shareDocument,
  accessSharedLink,
  manageAccess,
  revokeDocument,
  getAuditLog,
  getStats,
  getDocumentTypes,
  deleteDocument
} = require("../controllers/documentController");

const storage = multer.memoryStorage();
const upload = multer({
  storage,
  limits: {
    fileSize: 100 * 1024 * 1024
  },
  fileFilter: (req, file, cb) => {
    const allowedTypes = [
      "application/pdf",
      "image/jpeg",
      "image/png",
      "image/gif",
      "application/msword",
      "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
      "text/plain"
    ];
    if (allowedTypes.includes(file.mimetype)) {
      cb(null, true);
    } else {
      cb(new Error("Invalid file type"), false);
    }
  }
});

const validateUpload = [
  body("title").trim().notEmpty().withMessage("Title is required"),
  body("documentType").trim().notEmpty().withMessage("Document type is required"),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    next();
  }
];

const optionalMulterFile = (req, res, next) => {
  const ct = (req.headers["content-type"] || "").toLowerCase();
  if (ct.includes("application/json")) {
    return next();
  }
  return upload.single("file")(req, res, next);
};

router.post("/upload", authMiddleware, optionalMulterFile, validateUpload, uploadDocument);

router.get("/", authMiddleware, getDocuments);

router.get("/types", getDocumentTypes);

router.get("/stats", authMiddleware, getStats);

router.get("/:id", authMiddleware, getDocumentById);

router.post("/verify", authMiddleware, verifyDocument);

router.post("/:id/share", authMiddleware, shareDocument);

router.get("/shared/:linkId", accessSharedLink);

router.post("/:id/access", authMiddleware, manageAccess);

router.post("/:id/revoke", authMiddleware, revokeDocument);

router.get("/:id/audit", authMiddleware, getAuditLog);

router.delete("/:id", authMiddleware, deleteDocument);

router.use((err, req, res, next) => {
  if (err instanceof multer.MulterError) {
    if (err.code === "LIMIT_FILE_SIZE") {
      return res.status(400).json({ error: "File size exceeds 100MB limit" });
    }
    return res.status(400).json({ error: err.message });
  }
  if (err.message === "Invalid file type") {
    return res.status(400).json({ error: "Only PDF, images, Word docs, and text files are allowed" });
  }
  next(err);
});

module.exports = router;
